VALUES
  ('pukao-c5fb3965-moex-00494', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-110-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '關於都市計畫之行政爭訟，依現行行政訴訟法之規定，下列敘述何者正確？', '["凡依都市計畫法發布之都市計畫，皆得為行政法院審查之標的", "都市計畫審查程序中，擬定及核定都市計畫之機關，共同為被告機關", "都市計畫審查程序，專屬都市計畫區所在地之地方法院行政訴訟庭管轄", "行政法院審查如認都市計畫違法，應判決原告有理由，並撤銷該都市計畫"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00495', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-110-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '甲主張行政處分無效，向行政法院提起確認行政處分無效訴訟。依行政訴訟法之規定，下列敘述何者 正確？', '["甲提起之確認行政處分無效訴訟，並無應遵守之法定起訴期間規定", "甲應依訴願法提起訴願而不服其決定，始得提起確認行政處分無效訴訟", "如甲得提起撤銷訴訟或課予義務訴訟，不得提起確認行政處分無效訴訟", "如行政法院認為甲應提起課予義務訴訟，應裁定訴願管轄機關補提答辯狀"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00496', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-110-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '下列何者非屬以地方法院行政訴訟庭為第一審管轄法院之事件？', '["依入出國及移民法提起之收容異議事件", "請求判命行政機關應作成依法申請之建造執照", "請求撤銷依道路交通管理處罰條例作成之裁決", "請求確認行政機關所為新臺幣40萬元以下罰鍰處分為無效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00497', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-110-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '依國家賠償法之規定，關於國家賠償請求權之行使，下列敘述何者正確？', '["請求權人限於權利受損害之自然人，不包括法人", "因公務員行為所生之國家賠償責任，賠償義務人為從事該行為之公務員", "請求權人如未經協議程序，即向法院提起國家賠償訴訟，該訴訟不合法", "國家賠償之訴訟，除依國家賠償法之規定外，應準用行政訴訟法之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00498', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-110-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '甲之三合院古厝，長期出租他人作為廠房使用。嗣主管機關依法將其列為暫定古蹟，但因承租人之營 運可能破壞古蹟，致甲不得繼續出租。甲得基於下列何者，請求主管機關彌補其租金收益損失？', '["公法上不當得利返還請求權", "損失補償請求權", "國家賠償請求權", "公法上無因管理之管理費用請求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00499', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-110-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '關於徵收補償之敘述，下列何者正確？', '["須為合法公權力措施", "適用第一次權利保護優先原則", "當事人無須構成特別犧牲", "原公權力措施得預見其附帶違法侵害效果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00500', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-110-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '關於國家賠償法第3條公共設施之敘述，下列何者錯誤？', '["縱使尚未驗收合格之公共設施，如已開放公眾使用，仍有國家賠償法之適用", "公共設施之開放使用係屬行政機關事實行為", "私人所有之公共設施，亦有國家賠償法之適用", "公共設施設置地點之選定，屬公權力行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
