  ('pukao-d0d1b9a2-moex-00002', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-114-fa8ff513', 'sub-pukao-d0d1b9a2-01', NULL, 'essay', 'X5 年 1 月 1 日中央政府甲機關以$24,000,000 取得民營事業乙公司
